// Get all rows from Google Sheets
const rows = $input.all().map(item => item.json);

// ---- TOTAL REVENUE ----
const totalRevenue = rows.reduce((sum, row) => {
  return sum + parseFloat(row.Revenue || 0);
}, 0);

// ---- BEST PRODUCT ----
const productRevenue = {};
rows.forEach(row => {
  const product = row.Product;
  const rev = parseFloat(row.Revenue || 0);
  productRevenue[product] = (productRevenue[product] || 0) + rev;
});
const bestProduct = Object.entries(productRevenue)
  .sort((a, b) => b[1] - a[1])[0];

// ---- BEST REGION ----
const regionRevenue = {};
rows.forEach(row => {
  const region = row.Region;
  const rev = parseFloat(row.Revenue || 0);
  regionRevenue[region] = (regionRevenue[region] || 0) + rev;
});
const bestRegion = Object.entries(regionRevenue)
  .sort((a, b) => b[1] - a[1])[0];

// ---- BEST SALES REP ----
const repRevenue = {};
rows.forEach(row => {
  const rep = row.Sales_Rep;
  const rev = parseFloat(row.Revenue || 0);
  repRevenue[rep] = (repRevenue[rep] || 0) + rev;
});
const bestRep = Object.entries(repRevenue)
  .sort((a, b) => b[1] - a[1])[0];

// ---- BEST CATEGORY ----
const categoryRevenue = {};
rows.forEach(row => {
  const cat = row.Category;
  const rev = parseFloat(row.Revenue || 0);
  categoryRevenue[cat] = (categoryRevenue[cat] || 0) + rev;
});
const bestCategory = Object.entries(categoryRevenue)
  .sort((a, b) => b[1] - a[1])[0];

// ---- MoM CHANGE ----
const now = new Date();
const thisMonth = now.getMonth();
const lastMonth = thisMonth === 0 ? 11 : thisMonth - 1;

const thisMonthRev = rows
  .filter(row => new Date(row.Date).getMonth() === thisMonth)
  .reduce((sum, row) => sum + parseFloat(row.Revenue || 0), 0);

const lastMonthRev = rows
  .filter(row => new Date(row.Date).getMonth() === lastMonth)
  .reduce((sum, row) => sum + parseFloat(row.Revenue || 0), 0);

const momChange = lastMonthRev > 0
  ? (((thisMonthRev - lastMonthRev) / lastMonthRev) * 100).toFixed(1)
  : 'N/A';

const momArrow = parseFloat(momChange) >= 0 ? '📈' : '📉';

// ---- FORMAT NUMBERS ----
const formatNaira = (num) => 
  '₦' + num.toLocaleString('en-NG', {maximumFractionDigits: 0});

// ---- TOTAL ORDERS ----
const totalOrders = rows.length;

// ---- AVG ORDER VALUE ----
const avgOrderValue = totalRevenue / totalOrders;

// ---- RETURN RESULTS ----
return [{
  json: {
    reportDate: now.toDateString(),
    totalRevenue: formatNaira(totalRevenue),
    totalOrders: totalOrders,
    avgOrderValue: formatNaira(avgOrderValue),
    bestProduct: bestProduct[0],
    bestProductRevenue: formatNaira(bestProduct[1]),
    bestCategory: bestCategory[0],
    bestCategoryRevenue: formatNaira(bestCategory[1]),
    bestRegion: bestRegion[0],
    bestRegionRevenue: formatNaira(bestRegion[1]),
    bestSalesRep: bestRep[0],
    bestSalesRepRevenue: formatNaira(bestRep[1]),
    thisMonthRevenue: formatNaira(thisMonthRev),
    lastMonthRevenue: formatNaira(lastMonthRev),
    momChange: `${momChange}%`,
    momArrow: momArrow
  }
}];
